+  if (this->part_modes_.find(part) == this->part_modes_.end()) {
+    throw out_of_range("Part mode for part '" + part + "' not available in mode '" +
+            this->name_ + "', has to be present in default mode.");
+  }
+
+  this->add_part_mode(part, stateAndMode);
+}
