+
+using namespace std::chrono_literals;
+
+namespace system_modes
+{
+namespace examples
+{
+
+// DriveBase node with two non-default modes: weak and strong
+class DriveBase : public LifecycleNode
+{
+public:
+  explicit DriveBase()
+  : LifecycleNode("drive_base")
+  {
+    RCLCPP_INFO(get_logger(), "Constructed lifecycle node '%s'", this->get_name());
+
+    auto param_change_callback =
+    [this](std::vector<rclcpp::Parameter> parameters) -> rcl_interfaces::msg::SetParametersResult
+    {
+      auto result = rcl_interfaces::msg::SetParametersResult();
+      result.successful = true;
+      for (auto parameter : parameters) {
+        RCLCPP_INFO(this->get_logger(),
+          "parameter '%s' is now: %s",
+          parameter.get_name().c_str(),
+          parameter.value_to_string().c_str()
+          );
+      }
+      return result;
+    };
+    this->register_param_change_callback(param_change_callback);
+  }
+
+  DriveBase(const DriveBase &) = delete;
+  ~DriveBase() = default;
+
+  rcl_lifecycle_transition_key_t on_configure(const rclcpp_lifecycle::State &)
+  {
+    RCLCPP_INFO(get_logger(), "on_configure()", this->get_name());
+
+    return lifecycle_msgs::msg::Transition::TRANSITION_CALLBACK_SUCCESS;
+  };
+
+  rcl_lifecycle_transition_key_t on_activate(const rclcpp_lifecycle::State &)
+  {
+    RCLCPP_INFO(get_logger(), "on_activate()", this->get_name());
+
+    return lifecycle_msgs::msg::Transition::TRANSITION_CALLBACK_SUCCESS;
+  };
+
+  rcl_lifecycle_transition_key_t on_deactivate(const rclcpp_lifecycle::State &)
+  {
+    RCLCPP_INFO(get_logger(), "on_deactivate()", this->get_name());
+
+    return lifecycle_msgs::msg::Transition::TRANSITION_CALLBACK_SUCCESS;
+  };
+
+  rcl_lifecycle_transition_key_t on_cleanup(const rclcpp_lifecycle::State &)
+  {
+    RCLCPP_INFO(get_logger(), "on_cleanup()", this->get_name());
+
+    return lifecycle_msgs::msg::Transition::TRANSITION_CALLBACK_SUCCESS;
+  };
+};
+
+}  // namespace examples
+}  // namespace system_modes
+
+int main(int argc, char * argv[])
+{
+  setvbuf(stdout, NULL, _IONBF, BUFSIZ);
+
+  rclcpp::init(argc, argv);
+  rclcpp::executors::SingleThreadedExecutor exe;
+
+  auto driver = std::make_shared<system_modes::examples::DriveBase>();
+  exe.add_node(driver->get_node_base_interface());
+  exe.spin();
+
+  rclcpp::shutdown();
+
+  return 0;
+}

